"use client";
import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import type { Instance } from "@/lib/schema";

const JOB_TYPES = [
  { value: "check_updates", label: "Check for updates" },
  { value: "install_updates", label: "Install all updates" },
  { value: "install_updates_security", label: "Install security updates only" },
  { value: "install_package", label: "Install package(s)…" },
  { value: "run_command", label: "Run shell command…" },
  { value: "reboot", label: "Reboot" },
];

function statusBadge(inst: Instance) {
  if (!inst.lastSeen) return <span className="badge muted">never seen</span>;
  const age = Date.now() - inst.lastSeen;
  if (age < 90_000) return <span className="badge green">online</span>;
  if (age < 10 * 60_000) return <span className="badge amber">stale</span>;
  return <span className="badge red">offline</span>;
}

function timeAgo(ts: number | null): string {
  if (!ts) return "—";
  const s = Math.floor((Date.now() - ts) / 1000);
  if (s < 60) return `${s}s ago`;
  if (s < 3600) return `${Math.floor(s / 60)}m ago`;
  if (s < 86400) return `${Math.floor(s / 3600)}h ago`;
  return `${Math.floor(s / 86400)}d ago`;
}

export default function BulkActionBar({ instances }: { instances: Instance[] }) {
  const router = useRouter();
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [jobType, setJobType] = useState("check_updates");
  const [extra, setExtra] = useState("");
  const [busy, setBusy] = useState(false);

  const toggle = (id: string) => {
    const next = new Set(selected);
    next.has(id) ? next.delete(id) : next.add(id);
    setSelected(next);
  };
  const toggleAll = () => {
    if (selected.size === instances.length) setSelected(new Set());
    else setSelected(new Set(instances.map((i) => i.id)));
  };

  const submit = async () => {
    if (!selected.size) return;
    setBusy(true);
    try {
      let type = jobType;
      let payload: Record<string, unknown> = {};
      if (jobType === "install_updates_security") {
        type = "install_updates";
        payload = { security_only: true };
      } else if (jobType === "install_package") {
        payload = { packages: extra.split(/[\s,]+/).filter(Boolean) };
      } else if (jobType === "run_command") {
        payload = { command: extra };
      }
      const res = await fetch("/api/admin/jobs", {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          instance_ids: [...selected],
          type,
          payload,
        }),
      });
      if (!res.ok) {
        alert(`Failed: ${res.status} ${await res.text()}`);
      } else {
        setSelected(new Set());
        setExtra("");
        router.refresh();
      }
    } finally {
      setBusy(false);
    }
  };

  const needsExtra =
    jobType === "install_package" || jobType === "run_command";

  return (
    <>
      <div className="toolbar">
        <div className="row">
          <strong>{selected.size}</strong>
          <span className="muted">of {instances.length} selected</span>
        </div>
        <div className="row">
          <select
            value={jobType}
            onChange={(e) => setJobType(e.target.value)}
            disabled={busy}
          >
            {JOB_TYPES.map((t) => (
              <option key={t.value} value={t.value}>{t.label}</option>
            ))}
          </select>
          {needsExtra && (
            <input
              placeholder={
                jobType === "install_package"
                  ? "nginx, curl, ..."
                  : "uname -a"
              }
              value={extra}
              onChange={(e) => setExtra(e.target.value)}
              style={{ width: 280 }}
            />
          )}
          <button
            onClick={submit}
            disabled={busy || !selected.size || (needsExtra && !extra.trim())}
          >
            {busy ? "Dispatching…" : "Dispatch job"}
          </button>
        </div>
      </div>

      <table>
        <thead>
          <tr>
            <th style={{ width: 28 }}>
              <input
                type="checkbox"
                checked={
                  instances.length > 0 && selected.size === instances.length
                }
                onChange={toggleAll}
              />
            </th>
            <th>Hostname</th>
            <th>Status</th>
            <th>OS</th>
            <th>Kernel</th>
            <th>Pkg mgr</th>
            <th>Updates</th>
            <th>Security</th>
            <th>Last seen</th>
          </tr>
        </thead>
        <tbody>
          {instances.length === 0 && (
            <tr>
              <td colSpan={9} className="empty">
                No instances enrolled yet. Go to <Link href="/enroll">Enroll</Link>{" "}
                to add your first host.
              </td>
            </tr>
          )}
          {instances.map((i) => (
            <tr key={i.id}>
              <td>
                <input
                  type="checkbox"
                  checked={selected.has(i.id)}
                  onChange={() => toggle(i.id)}
                />
              </td>
              <td>
                <Link href={`/instances/${i.id}`}>{i.hostname}</Link>
              </td>
              <td>{statusBadge(i)}</td>
              <td>
                {i.osName ?? "—"}{" "}
                <span className="muted">{i.osVersion ?? ""}</span>
              </td>
              <td className="muted">{i.kernel ?? "—"}</td>
              <td>
                <span className="badge blue">{i.pkgManager ?? "?"}</span>
              </td>
              <td>{i.updatesAvailable}</td>
              <td>
                {i.securityUpdates > 0 ? (
                  <span className="badge red">{i.securityUpdates}</span>
                ) : (
                  <span className="muted">0</span>
                )}
              </td>
              <td className="muted">{timeAgo(i.lastSeen)}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );
}
